<template>
  <div class="progress-container" :class="{ 'mobile-view': isMobile }">
    <div class="progress-steps">
      <!-- 第一个节点 -->
      <div 
        class="progress-step first-step"
        :class="{ active: currentStep === 1, completed: currentStep > 1 }"
      >
        <div class="step-number">
          <span v-if="currentStep > 1" class="check-icon">✓</span>
          <span v-else>1</span>
        </div>
        <div class="step-label">{{ steps[0] }}</div>
        <div v-if="currentStep === 1" class="step-shadow"></div>
      </div>
      
      <!-- 中间连接线 -->
      <div class="connector-line">
        <div class="connector-line-completed" :style="{ width: currentStep > 1 ? '100%' : '0%' }"></div>
        <div class="connector-line-pending" :style="{ width: currentStep > 1 ? '0%' : '100%' }"></div>
      </div>
      
      <!-- 第二个节点 -->
      <div 
        class="progress-step"
        :class="{ active: currentStep === 2, completed: currentStep > 2 }"
      >
        <div class="step-number">
          <span v-if="currentStep > 2" class="check-icon">✓</span>
          <span v-else>2</span>
        </div>
        <div class="step-label">{{ steps[1] }}</div>
        <div v-if="currentStep === 2" class="step-shadow"></div>
      </div>
      
      <!-- 中间连接线 -->
      <div class="connector-line">
        <div class="connector-line-completed" :style="{ width: currentStep > 2 ? '100%' : '0%' }"></div>
        <div class="connector-line-pending" :style="{ width: currentStep > 2 ? '0%' : '100%' }"></div>
      </div>
      
      <!-- 第三个节点 -->
      <div 
        class="progress-step"
        :class="{ active: currentStep === 3, completed: currentStep > 3 }"
      >
        <div class="step-number">
          <span v-if="currentStep > 3" class="check-icon">✓</span>
          <span v-else>3</span>
        </div>
        <div class="step-label">{{ steps[2] }}</div>
        <div v-if="currentStep === 3" class="step-shadow"></div>
      </div>
      
      <!-- 中间连接线 -->
      <div class="connector-line">
        <div class="connector-line-completed" :style="{ width: currentStep > 3 ? '100%' : '0%' }"></div>
        <div class="connector-line-pending" :style="{ width: currentStep > 3 ? '0%' : '100%' }"></div>
      </div>
      
      <!-- 第四个节点 -->
      <div 
        class="progress-step last-step"
        :class="{ active: currentStep === 4, completed: currentStep > 4 }"
      >
        <div class="step-number">
          <span v-if="currentStep > 4" class="check-icon">✓</span>
          <span v-else>4</span>
        </div>
        <div class="step-label">{{ steps[3] }}</div>
        <div v-if="currentStep === 4" class="step-shadow"></div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'ProgressBar',
  props: {
    currentStep: {
      type: Number,
      required: true
    },
    steps: {
      type: Array,
      default: () => ['Business Info', 'Service', 'Contact', 'Account']
    },
    isMobile: {
      type: Boolean,
      default: false
    }
  }
}
</script>

<style scoped>
.progress-container {
  margin-bottom: 40px;
}

.progress-steps {
  position: relative;
  display: flex;
  align-items: flex-start;
  margin-bottom: 30px;
}

.progress-step {
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  z-index: 2;
  flex: 1;
}

.first-step, .last-step {
  flex: 0 0 auto;
  width: 80px;
}

/* 中间连接线 */
.connector-line {
  flex: 1;
  height: 2px;
  position: relative;
  margin: 0 10px;
  z-index: 1;
  display: flex;
  margin-top: 20px;
}

.connector-line-completed {
  height: 100%;
  background-color: #4CAF50;
  transition: width 0.3s ease;
}

.connector-line-pending {
  height: 100%;
  background-color: #E0E0E0;
  transition: width 0.3s ease;
}

/* 选中节点的阴影效果 */
.step-shadow {
  position: absolute;
  top: -5px;
  left: 50%;
  transform: translateX(-50%);
  width: 55px;
  height: 55px;
  border-radius: 50%;
  background-color: rgba(255, 107, 0, 0.1);
  z-index: -1;
  transition: all 0.3s ease;
}

.step-number {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background-color: #FFFFFF;
  color: #999999;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: bold;
  margin-bottom: 8px;
  transition: all 0.3s ease;
  border: 2px solid #E0E0E0;
}

.step-label {
  font-size: 14px;
  color: #999999;
  transition: all 0.3s ease;
  text-align: center;
}

.check-icon {
  font-size: 20px;
  font-weight: bold;
}

/* 已完成状态 */
.progress-step.completed .step-number {
  background-color: #4CAF50;
  color: white;
  border-color: #4CAF50;
}

.progress-step.completed .step-label {
  color: #4CAF50;
}

/* 当前状态 */
.progress-step.active .step-number {
  background-color: #FF6B00;
  color: white;
  border-color: #FF6B00;
}

.progress-step.active .step-label {
  color: #FF6B00;
  font-weight: 600;
}
.progress-container.mobile-view {
  margin-bottom: 20px;
}

.progress-container.mobile-view .progress-steps {
  margin-bottom: 15px;
}

.progress-container.mobile-view .step-number {
  width: 25px;
  height: 25px;
  font-size: 12px;
  margin-bottom: 4px;
  border-width: 1px;
}

.progress-container.mobile-view .step-label {
  font-size: 10px;
}

.progress-container.mobile-view .connector-line {
  flex: 1;
  height: 1px;
  position: relative;
  margin: 0 5px;
  z-index: 1;
  display: flex;
  margin-top: 12.5px;
}

.progress-container.mobile-view .first-step, 
.progress-container.mobile-view .last-step {
  width: 40px;
}

.progress-container.mobile-view .step-shadow {
  width: 35px;
  height: 35px;
  top: -4px;
}

.progress-container.mobile-view .check-icon {
  font-size: 12px;
}
</style>